const raw = $input.first().json;
const body = raw.body || raw;
const payload = body.$json || body;

const preview = payload.preview === true || payload.preview === 'true';
const org_id = payload.org_id || null;
let website_url = (payload.website_url || payload.website || '').trim();

if (!website_url) {
  throw new Error('Missing required field: website_url');
}
if (!preview && !org_id) {
  throw new Error('Missing required field: org_id (required unless preview=true)');
}

if (!/^https?:\/\//i.test(website_url)) {
  website_url = 'https://' + website_url;
}
website_url = website_url.replace(/#.*$/, '').replace(/\/$/, '');

// Parse origin manually — URL global isn't always available in task-runner sandbox
const originMatch = website_url.match(/^(https?:\/\/[^\/]+)/i);
if (!originMatch) {
  throw new Error(`Invalid website_url: ${website_url}`);
}
const origin = originMatch[1];

return [{ json: { org_id, website_url, origin, preview } }];

// Fetches homepage, picks up to 5 same-origin subpages of interest, fetches them, and returns combined cleaned text.
const helpers = this.helpers;
const { org_id, website_url, origin, preview } = $input.first().json;

const USER_AGENT = 'Mozilla/5.0 (compatible; FundoryBot/1.0; +https://fundory.app)';
const PAGE_TIMEOUT_MS = 15000;
const MAX_SUBPAGES = 5;
const MAX_TOTAL_CHARS = 16000;

function stripHtml(s) {
  if (!s) return '';
  return s
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
    .replace(/<!--([\s\S]*?)-->/g, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

async function fetchPage(url) {
  try {
    const res = await helpers.httpRequest({
      method: 'GET',
      url,
      headers: { 'User-Agent': USER_AGENT, 'Accept': 'text/html,application/xhtml+xml' },
      timeout: PAGE_TIMEOUT_MS,
      returnFullResponse: false,
      json: false,
      followRedirect: true,
    });
    return typeof res === 'string' ? res : (res && res.body) || '';
  } catch (e) {
    return '';
  }
}

function parseUrl(href) {
  const m = href.match(/^(https?:\/\/[^\/]+)(\/[^?]*)?/i);
  if (!m) return null;
  return { origin: m[1], pathname: m[2] || '/' };
}
function findSubpages(html) {
  const linkRe = /<a\b[^>]*href=["']([^"'#]+)["'][^>]*>([\s\S]*?)<\/a>/gi;
  const keywords = ['about', 'mission', 'who-we-are', 'whoweare', 'our-story', 'history', 'programs', 'program', 'services', 'what-we-do', 'whatwedo', 'impact', 'outcomes', 'team', 'leadership', 'staff'];
  const seen = new Set();
  const found = [];
  let m;
  while ((m = linkRe.exec(html)) !== null) {
    let href = m[1];
    const label = stripHtml(m[2] || '').toLowerCase();
    if (href.startsWith('//')) href = 'https:' + href;
    else if (href.startsWith('/')) href = origin + href;
    else if (!/^https?:\/\//i.test(href)) continue;
    const u = parseUrl(href);
    if (!u) continue;
    if (u.origin !== origin) continue;
    if (/\.(jpg|jpeg|png|gif|svg|webp|pdf|zip|mp4|mp3)$/i.test(u.pathname)) continue;
    const lowered = (u.pathname + ' ' + label).toLowerCase();
    if (!keywords.some(k => lowered.includes(k))) continue;
    const key = u.origin + u.pathname;
    if (seen.has(key)) continue;
    if (key === website_url) continue;
    seen.add(key);
    found.push(key);
    if (found.length >= MAX_SUBPAGES) break;
  }
  return found;
}

const homeHtml = await fetchPage(website_url);
if (!homeHtml || homeHtml.length < 200) {
  throw new Error(`Could not fetch homepage at ${website_url} (empty or too small response)`);
}
const homeText = stripHtml(homeHtml);

const subpageUrls = findSubpages(homeHtml);

const pages = [{ url: website_url, label: 'Homepage', text: homeText }];
for (const u of subpageUrls) {
  const html = await fetchPage(u);
  if (!html) continue;
  const text = stripHtml(html);
  if (text.length < 200) continue;
  pages.push({ url: u, label: 'Subpage', text });
}

let remaining = MAX_TOTAL_CHARS;
const sections = [];
for (const p of pages) {
  if (remaining <= 0) break;
  const slice = p.text.slice(0, Math.min(p.text.length, remaining));
  sections.push(`### ${p.label}: ${p.url}\n${slice}`);
  remaining -= slice.length;
}

return [{
  json: {
    org_id,
    website_url,
    preview,
    page_count: pages.length,
    combined_text: sections.join('\n\n'),
  }
}];

const ai = $input.first().json;
const src = $('Scrape Site').first().json;

let parsed = ai && ai.message && ai.message.content;

if (typeof parsed === 'string') {
  let cleaned = parsed.trim().replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  try { parsed = JSON.parse(cleaned); }
  catch (e) { throw new Error('OpenAI response was not valid JSON: ' + cleaned.slice(0, 300)); }
}

if (!parsed || typeof parsed !== 'object') {
  throw new Error('No usable JSON returned from OpenAI node');
}

const SECTION_TITLES = {
  mission: 'Mission Statement',
  community_need: 'Community Need',
  programs: 'Programs & Services',
  impact: 'Impact & Outcomes',
  history: 'Organization History',
  leadership: 'Leadership & Team',
};

const out = [];
for (const [key, title] of Object.entries(SECTION_TITLES)) {
  const content = (parsed[key] || '').toString().trim();
  if (!content) continue;
  out.push({
    json: {
      org_id: src.org_id,
      ai_category: 'narrative_' + key,
      title,
      content,
      source_url: src.website_url,
      preview: src.preview,
    }
  });
}

if (out.length === 0) {
  throw new Error('OpenAI returned no usable sections from the website content');
}

return out;

const src = $('Scrape Site').first().json;
const sectionItems = $('Split Sections').all().map(i => i.json);

// Inserted rows (only present in non-preview path) come from $input — flatten Supabase return arrays.
const inserted = [];
for (const item of $input.all()) {
  const j = item.json;
  if (Array.isArray(j)) {
    for (const r of j) if (r && r.id) inserted.push(r);
  } else if (j && j.id) {
    inserted.push(j);
  }
}

// Always echo the generated narratives so the caller can render/edit them.
const narratives = sectionItems.map(s => ({
  ai_category: s.ai_category,
  title: s.title,
  content: s.content,
}));

return [{
  json: {
    success: true,
    preview: !!src.preview,
    org_id: src.org_id,
    website_url: src.website_url,
    pages_scraped: src.page_count,
    narratives,
    narratives_inserted: inserted.length,
    document_ids: inserted.map(d => d.id).filter(Boolean),
    generated_at: new Date().toISOString(),
  }
}];
